import React, { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { MapPin, QrCode, Shield, Bell, ChevronRight, BookOpen } from 'lucide-react'

const LIBRARY_IMG = ""
const SEATTYPE_IMG = ""

export default function LandingPage() {
  const navigate = useNavigate()
  const [counts, setCounts] = useState({ free: 120, occupied: 150, away: 30 })

  useEffect(() => {
    const interval = setInterval(() => {
      setCounts(prev => ({
        free: Math.max(100, Math.min(140, prev.free + Math.floor(Math.random() * 3) - 1)),
        occupied: prev.occupied,
        away: Math.max(20, Math.min(40, prev.away + Math.floor(Math.random() * 3) - 1)),
      }))
    }, 3000)
    return () => clearInterval(interval)
  }, [])

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Navbar */}
      <nav className="bg-white border-b border-gray-100 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-9 h-9 bg-primary rounded-xl flex items-center justify-center">
              <BookOpen size={18} color="white" />
            </div>
            <span className="text-xl font-bold text-gray-900">SeatWise</span>
          </div>
          <div className="hidden md:flex items-center gap-8">
            {['Home', 'Features', 'How it Works', 'Contact'].map(item => (
              <a key={item} href="#" className="text-gray-600 hover:text-gray-900 text-sm font-medium transition-colors">{item}</a>
            ))}
          </div>
          <button
            onClick={() => navigate('/login')}
            className="bg-primary text-white px-5 py-2.5 rounded-xl font-semibold text-sm hover:bg-primary-dark transition-colors"
          >
            Login
          </button>
        </div>
      </nav>

      {/* Hero */}
      <section className="max-w-7xl mx-auto px-6 py-16 md:py-24 grid md:grid-cols-2 gap-12 items-center">
        <div>
          <div className="inline-flex items-center gap-2 bg-primary-light text-primary text-sm font-medium px-4 py-2 rounded-full mb-6">
            <span className="w-2 h-2 bg-primary rounded-full animate-pulse"></span>
            Live seat tracking · No hoarding
          </div>
          <h1 className="text-5xl md:text-6xl font-extrabold text-gray-900 leading-tight mb-6">
            Fair Library Seating{' '}
            <span className="text-primary">for Everyone</span>
          </h1>
          <p className="text-gray-500 text-lg leading-relaxed mb-8">
            Find the perfect seat for the way you study. Real-time availability, smart anti-hoarding, and a better library experience for all.
          </p>
          <div className="flex gap-4">
            <button
              onClick={() => navigate('/login')}
              className="bg-primary text-white px-7 py-3.5 rounded-xl font-semibold flex items-center gap-2 hover:bg-primary-dark transition-colors shadow-sm shadow-green-200"
            >
              View Library Map <ChevronRight size={16} />
            </button>
            <button className="border border-gray-200 text-gray-700 px-7 py-3.5 rounded-xl font-semibold hover:bg-gray-50 transition-colors">
              Learn More
            </button>
          </div>
        </div>

        {/* Hero card — library photo */}
        <div className="relative">
          <div className="rounded-2xl overflow-hidden h-80 relative shadow-lg">
            <img
              src={`data:image/jpeg;base64,${LIBRARY_IMG}`}
              alt="Library floor map preview"
              className="w-full h-full object-cover"
            />
            {/* overlay gradient */}
            <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent" />
            {/* Live badge */}
            <div className="absolute bottom-4 left-4 bg-white rounded-2xl shadow-lg px-5 py-3">
              <div className="flex items-center gap-2 mb-2">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                <span className="text-xs font-semibold text-gray-600">Live — Floor 1</span>
              </div>
              <div className="flex gap-5">
                <div className="text-center">
                  <p className="text-2xl font-bold text-green-600">{counts.free}</p>
                  <p className="text-xs text-gray-400">Free</p>
                </div>
                <div className="text-center">
                  <p className="text-2xl font-bold text-red-500">{counts.occupied}</p>
                  <p className="text-xs text-gray-400">Occupied</p>
                </div>
                <div className="text-center">
                  <p className="text-2xl font-bold text-yellow-500">{counts.away}</p>
                  <p className="text-xs text-gray-400">Away</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Features */}
      <section className="max-w-7xl mx-auto px-6 pb-16 grid grid-cols-2 md:grid-cols-4 gap-6">
        {[
          { icon: MapPin, title: 'Live Seat Tracking', desc: 'Real-time seat status at a glance' },
          { icon: QrCode, title: 'QR Check-In', desc: 'Secure and easy check-in process' },
          { icon: Shield, title: 'Anti-Hoarding', desc: 'Automatic timers & seat release' },
          { icon: Bell, title: 'Smart Notifications', desc: 'Stay updated with real-time alerts' },
        ].map(({ icon: Icon, title, desc }) => (
          <div key={title} className="bg-white rounded-2xl p-6 border border-gray-100 hover:shadow-md transition-shadow">
            <div className="w-10 h-10 bg-primary-light rounded-xl flex items-center justify-center mb-4">
              <Icon size={18} className="text-primary" />
            </div>
            <h3 className="font-semibold text-gray-900 mb-1">{title}</h3>
            <p className="text-sm text-gray-500">{desc}</p>
          </div>
        ))}
      </section>

      {/* Seat Types */}
      <section className="bg-white py-20">
        <div className="max-w-7xl mx-auto px-6">
          <p className="text-center text-xs font-bold tracking-widest text-primary uppercase mb-3">Seat Types</p>
          <h2 className="text-center text-4xl font-bold text-gray-900 mb-3">Choose the seat that fits your needs</h2>
          <p className="text-center text-gray-500 mb-12">Pick the right environment for the right kind of study.</p>
          <div className="grid md:grid-cols-3 gap-6">
            {[
              {
                label: 'SC',
                name: 'Solo Cubicle',
                desc: 'Quiet spaces for individual focus',
                count: 45,
                color: 'bg-green-50 border-green-200',
                dot: 'bg-green-500',
                imgStyle: { objectPosition: '0% 30%', filter: 'hue-rotate(0deg)' },
              },
              {
                label: 'G',
                name: 'Group Table',
                desc: 'Collaborative spaces for teams',
                count: 10,
                color: 'bg-blue-50 border-blue-200',
                dot: 'bg-green-500',
                imgStyle: { objectPosition: '50% 30%', filter: 'hue-rotate(200deg) saturate(0.8)' },
              },
              {
                label: 'IS',
                name: 'Indoor Study Area',
                desc: 'Sound-insulated areas for group study',
                count: 4,
                color: 'bg-purple-50 border-purple-200',
                dot: 'bg-purple-500',
                imgStyle: { objectPosition: '100% 30%', filter: 'hue-rotate(260deg) saturate(0.7)' },
              },
            ].map(({ label, name, desc, count, color, dot, imgStyle }) => (
              <div key={name} className={`rounded-2xl border-2 ${color} p-6 hover:shadow-lg transition-shadow cursor-pointer`}>
                <div className="h-44 rounded-xl overflow-hidden mb-6 relative">
                  <img
                    src={`data:image/png;base64,${SEATTYPE_IMG}`}
                    alt={name}
                    className="w-full h-full object-cover scale-110"
                    style={imgStyle}
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent" />
                </div>
                <div className="flex items-start justify-between mb-2">
                  <h3 className="font-bold text-gray-900 text-lg">{name}</h3>
                  <span className={`text-xs font-bold px-2 py-1 rounded-lg ${dot === 'bg-purple-500' ? 'bg-purple-200 text-purple-700' : 'bg-green-200 text-green-700'}`}>{label}</span>
                </div>
                <p className="text-gray-500 text-sm mb-3">{desc}</p>
                <div className="flex items-center gap-1.5">
                  <span className={`w-2.5 h-2.5 rounded-full ${dot}`}></span>
                  <span className="text-sm font-semibold text-gray-700">Available: {count}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <section className="bg-primary py-16">
        <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row items-center justify-between gap-6">
          <div>
            <h2 className="text-3xl font-bold text-white mb-2">Ready to find your perfect study spot?</h2>
            <p className="text-green-100">Scan the QR code on any desk to check in, or browse the live map now.</p>
          </div>
          <button
            onClick={() => navigate('/login')}
            className="bg-white text-primary px-8 py-4 rounded-xl font-bold text-base hover:bg-green-50 transition-colors whitespace-nowrap"
          >
            Get Started
          </button>
        </div>
      </section>

      {/* Footer */}
      <footer className="bg-gray-900 text-gray-400 py-8 text-center text-sm">
        <p>© 2025 SeatWise. Fair library seating for everyone.</p>
      </footer>
    </div>
  )
}
